use std::fs::File;
use std::io::{self, BufReader, BufRead};

struct GridData {
    width: usize,
    height: usize,
    data: Vec<Vec<u8>>,
}

fn read_grid_from_file(filepath: &str) -> io::Result<GridData> {
    let file = File::open(filepath)?;
    let reader = BufReader::new(file);

    let mut lines = reader.lines();
    let first_line = match lines.next() {
        Some(Ok(line)) => line,
        _ => return Err(io::Error::new(io::ErrorKind::InvalidData, "Missing header line")),
    };

    let mut width = 0;
    let mut height = 0;

    if !first_line.is_empty() { 
        width = first_line.split_whitespace().map(|s| s.parse::<usize>().unwrap()).product();
    }

    let mut data: Vec<Vec<u8>> = Vec::new();
    for line_result in lines {
        let line = line_result?;
        if line.trim().is_empty() { 
            continue;
        }
        let row: Vec<u8> = line.split_whitespace().map(|s| s.parse::<u8>().unwrap()).collect();
        data.push(row);
    }

    let height_actual = data.len();

    Ok(GridData {
        width: width.max(1).min(2048),
        height: height_actual,
        data,
    })
}

use std::fs::File;
use std::io::{self, Read, Write};

struct FirmwareImage {
    version: String,
    payload_size: u32,
    data: Vec<u8>,
}

fn parse_firmware(path: &str) -> io::Result<FirmwareImage> {
    let mut file = File::open(path)?;
    let mut header_buffer = [0u8; 12];
    file.read_exact(&mut header_buffer)?;

    let version_bytes = &header_buffer[0..8];
    let payload_size = u32::from_le_bytes(header_buffer[8..12].try_into().unwrap());

    let version = String::from_utf8_lossy(version_bytes).to_string();

    let mut data = vec![0u8; payload_size as usize];
    file.read_exact(&mut data)?;

    Ok(FirmwareImage {
        version,
        payload_size: payload_size as u32,
        data,
    })
}

fn main() -> io::Result<()> {
    let test_path = "test_firmware.bin";
    create_dummy_binary(test_path, "v1.2.0", 50)?;

    match parse_firmware(test_path) {
        Ok(img) => println!("Successfully parsed image: Version={} | Payload Size={}", img.version, img.payload_size),
        Err(e) => eprintln!("Error during parsing: {}", e)
    }

    Ok(())
}

fn create_dummy_binary(path: &str, version: &str, size: usize) -> io::Result<()> {
    let mut buffer = Vec::new();
    buffer.write_all(version.as_bytes())?;
    let size_bytes = (size as u32).to_le_bytes();
    buffer.write_all(&size_bytes)?;
    buffer.resize(12 + size, 0xAA);

    let mut file = File::create(path)?;
    file.write_all(&buffer)?;
    Ok(())
}

use std::collections::HashMap;

struct ConfigParser {
    settings: HashMap<String, String>,
}

impl ConfigParser {
    fn new() -> Self {
        ConfigParser { settings: HashMap::new() }
    }

    fn parse_block(&mut self, raw_text: &str) -> Result<(), String> {
        let lines = raw_text.trim().lines();
        let mut current_key = String::from("unknown");

        for line in lines {
            let trimmed_line = line.trim();
            if trimmed_line.is_empty() { continue; }

            if let Some((key, value)) = trimmed_line.split_once(":") {
                let key_trimmed = key.trim().to_string();
                let value_trimmed = value.trim().to_string();
                self.settings.insert(key_trimmed, value_trimmed);
            } else if line.starts_with("key=") && !line.contains(":") {
                current_key = line.split("=").nth(1).unwrap_or(&String::from("unknown")).trim().to_string();
            }
        }
        Ok(())
    }

    fn get_setting(&self, key: &str) -> Option<&String> {
        self.settings.get(key)
    }
}

use std::iter::Peekable;

#[derive(Debug, Clone)]
enum Token {
    Number(f64),
    Identifier(String),
    Operator(char),
    LParen,
    RParen,
}

struct Lexer<'a> {
    input: Peekable<std::str::Chars<'a>>,
}

impl<'a> Lexer<'a> {
    fn new(text: &'a str) -> Self {
        Lexer { 
            input: text.chars().peekable()
        }
    }

    fn next_token(&mut self) -> Option<Token> {
        let mut char = match self.input.next() {
            Some(c) => c,
            None => return None,
        };

        if char.is_whitespace() {
            return self.next_token();
        }

        match char {
            '(' => Some(Token::LParen),
            ')' => Some(Token::RParen),
            '+' | '-' | '*' | '/' | '^' => Some(Token::Operator(char)),
            '0'..='9' | '.' => {
                let mut num_str = String::new();
                num_str.push(char);
                while let Some(&next_char) = self.input.peek() {
                    if next_char.is_ascii_digit() || next_char == '.' {
                        num_str.push(next_char);
                        self.input.next();
                    } else {
                        break;
                    }
                }
                Some(Token::Number(num_str.parse().unwrap()))
            }
            'a'..='z' | 'A'..='Z' | '_' => {
                let mut ident_str = String::new();
                ident_str.push(char);
                while let Some(&next_char) = self.input.peek() {
                    if next_char.is_ascii_alphanumeric() || next_char == '_' {
                        ident_str.push(next_char);
                        self.input.next();
                    } else {
                        break;
                    }
                }
                Some(Token::Identifier(ident_str))
            }
            _ => None,
        }
    }
}

fn main() {
    let expression = "2.5 * (x + 3) / y";
    let mut lexer = Lexer::new(expression);

    println!("Lexing: {}", expression);

    let mut tokens: Vec<Token> = Vec::new();
    loop {
        match lexer.next_token() {
            Some(token) => {
                tokens.push(token);
            }
            None => break,
        }
    }

    println!("nGenerated Tokens:");
    for token in tokens {
        println!("{:?}", token);
    }
}

use std::collections::HashMap;

struct Token {
    kind: TokenType,
    value: String,
}

#[derive(Debug, PartialEq)]
enum TokenType {
    Identifier,
    EqualsSign,
    Whitespace,
    EndOfFile,
}

fn tokenize(input: &str) -> Vec<Token> {
    let mut tokens = Vec::new();
    let mut chars = input.chars().peekable();

    while let Some(c) = chars.next() {
        if c.is_whitespace() {
            tokens.push(Token { kind: TokenType::Whitespace, value: String::from(&c.to_string()) });
            continue;
        }

        if c.is_alphanumeric() || c == '-' {
            let mut value = String::new();
            value.push(c);
            while let Some(&next_c) = chars.peek() {
                if next_c.is_alphanumeric() || next_c == '-' {
                    value.push(chars.next().unwrap());
                } else {
                    break;
                }
            }
            tokens.push(Token { kind: TokenType::Identifier, value });
            continue;
        }

        if c == '=' {
            tokens.push(Token { kind: TokenType::EqualsSign, value: String::from(&c.to_string()) });
            continue;
        }

        tokens.push(Token { kind: TokenType::EndOfFile, value: String::from(&c.to_string()) });
    }
    tokens
}

fn main() {
    let input = "server-name = my-appnport = 8080";
    let tokens = tokenize(input);
    for token in &tokens {
        println!("{:?}: {}", token.kind, token.value);
    }
}
